import com.pinterest.ktlint.test.KtLintAssertThat
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import org.junit.jupiter.api.Test

/**
 * Tests for BinaryExpressionWrappingRule with elvis operator to ensure no endless loop occurs.
 */
class BinaryExpressionWrappingRuleElvisTest {
    private val binaryExpressionWrappingRuleAssertThat = KtLintAssertThat.assertThatRule { BinaryExpressionWrappingRule() }

    @Test
    fun `Given a binary expression with elvis operator that exceeds max line length, then do not wrap after elvis operator to avoid conflict with chain-wrapping rule`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                           $EOL_CHAR
            val foo =
                bar
                    ?:
                    throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        // The rule should not attempt to wrap after the elvis operator as that would conflict with chain-wrapping rule
        // which requires elvis operator to be at the start of a line, not at the end
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { ChainWrappingRule() }
            .hasNoLintViolations()
    }

    @Test
    fun `Given a binary expression with elvis operator on same line that exceeds max line length`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                           $EOL_CHAR
            val foo = bar ?: throw UnsupportedOperationException("x")
            """.trimIndent()
        // When the line exceeds max line length, wrapping after elvis is not allowed
        // The violation should be reported but not auto-corrected to prevent endless loop
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .hasLintViolationWithoutAutoCorrect(2, 11, "Line is exceeding max line length. Break line between assignment and expression")
    }

    @Test
    fun `Given a binary expression with dot operator that exceeds max line length, then do not wrap after dot operator`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                           $EOL_CHAR
            val foo =
                someObject.property ?: "default value that is long"
            """.trimIndent()
        // The rule should not wrap after the dot operator
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .hasLintViolationWithoutAutoCorrect(3, 20, "Line is exceeding max line length")
    }

    @Test
    fun `Given a binary expression with safe access operator that exceeds max line length, then do not wrap after safe access operator`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                           $EOL_CHAR
            val foo =
                someObject?.property ?: "default value that is long"
            """.trimIndent()
        // The rule should not wrap after the safe access operator
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .hasLintViolationWithoutAutoCorrect(3, 21, "Line is exceeding max line length")
    }

    @Test
    fun `Given a binary expression with regular operator like plus that exceeds max line length, then wrap after operator`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                           $EOL_CHAR
            val foo =
                "some long string value" + "another long string value"
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                           $EOL_CHAR
            val foo =
                "some long string value" +
                    "another long string value"
            """.trimIndent()
        // Regular operators (not elvis, dot, or safe access) can be wrapped normally
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .hasLintViolation(3, 30, "Line is exceeding max line length. Break line after operator in binary expression")
            .isFormattedAs(formattedCode)
    }
}
"}

