/**
 * Tests for BinaryExpressionWrappingRule with elvis operator to ensure no endless loop occurs.
 */
class BinaryExpressionWrappingRuleElvisTest {
    private val binaryExpressionWrappingRuleAssertThat = KtLintAssertThat.assertThatRule { BinaryExpressionWrappingRule() }

    @Test
    fun `Given a binary expression with elvis operator that exceeds max line length, then do not wrap after elvis operator to avoid conflict with chain-wrapping rule`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                           $EOL_CHAR
            val foo =
                bar
                    ?:
                    throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                           $EOL_CHAR
            val foo =
                bar
                        ?: throw UnsupportedOperationException("xxxxxxxxxxx")
            """.trimIndent()
        // The binary-expression-wrapping rule reports the violation but does not auto-correct
        // to avoid conflict with chain-wrapping rule. The chain-wrapping rule then formats
        // the code by moving the elvis operator to the start of the line.
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { ChainWrappingRule() }
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a binary expression with elvis operator on same line that exceeds max line length`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                           $EOL_CHAR
            val foo = bar ?: throw UnsupportedOperationException("x")
            """.trimIndent()
        // When the line exceeds max line length, the elvis operator is detected but wrapping
        // after it is not auto-corrected to avoid conflict with chain-wrapping
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .hasLintViolationWithoutAutoCorrect(2, 15, "Line is exceeding max line length")
    }

    @Test
    fun `Given a binary expression with regular operator like plus that exceeds max line length, then wrap after operator`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                           $EOL_CHAR
            val foo =
                "some long string value" + "another long string value"
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                           $EOL_CHAR
            val foo =
                "some long string value" +
                    "another long string value"
            """.trimIndent()
        // Regular operators (not elvis) can be wrapped normally
        binaryExpressionWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .hasLintViolation(3, 31, "Line is exceeding max line length. Break line after operator in binary expression")
            .isFormattedAs(formattedCode)
    }
}
"}

